-- Modify "chat_sessions" table
ALTER TABLE "chat_sessions" ADD COLUMN "approval_mode" character varying NOT NULL DEFAULT 'single';
-- Create "chat_session_approvals" table
CREATE TABLE "chat_session_approvals" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "conclusion_digest" character varying NOT NULL,
  "actor_subject" character varying NOT NULL,
  "authority" character varying NOT NULL,
  "reason" character varying NOT NULL,
  "approved_at" timestamptz NOT NULL,
  "created_at" timestamptz NOT NULL,
  "chat_session_id" bigint NOT NULL,
  PRIMARY KEY ("id"),
  CONSTRAINT "chat_session_approvals_chat_sessions_approvals" FOREIGN KEY ("chat_session_id") REFERENCES "chat_sessions" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION
);
-- Create index "chatsessionapproval_actor_subject_approved_at" to table: "chat_session_approvals"
CREATE INDEX "chatsessionapproval_actor_subject_approved_at" ON "chat_session_approvals" ("actor_subject", "approved_at");
-- Create index "chatsessionapproval_chat_session_id_conclusion_digest_actor_sub" to table: "chat_session_approvals"
CREATE UNIQUE INDEX "chatsessionapproval_chat_session_id_conclusion_digest_actor_sub" ON "chat_session_approvals" ("chat_session_id", "conclusion_digest", "actor_subject");
-- Create index "chatsessionapproval_chat_session_id_conclusion_digest_authority" to table: "chat_session_approvals"
CREATE UNIQUE INDEX "chatsessionapproval_chat_session_id_conclusion_digest_authority" ON "chat_session_approvals" ("chat_session_id", "conclusion_digest", "authority");
-- Create index "chatsessionapproval_chat_session_id_conclusion_digest_approved_" to table: "chat_session_approvals"
CREATE INDEX "chatsessionapproval_chat_session_id_conclusion_digest_approved_" ON "chat_session_approvals" ("chat_session_id", "conclusion_digest", "approved_at");
